def intersection_nested_lists(list1, list2):
    if not isinstance(list2, list) or not all(isinstance(x, list) for x in list2):
        return []
    result = []
    for nested_list in list2:
        sublist = []
        for element in nested_list:
            if element in list1:
                sublist.append(element)
        result.append(sublist)
    return result

